import { beginnerLessonsExpanded } from "./beginnerLessonsExpanded";
import { beginnerLessonsSet2 } from "./beginnerLessonsSet2";
import { intermediateLessons } from "./intermediateLessons";
import { advancedLessons } from "./advancedLessons";
import { intermediateExtendedLessons } from "./intermediateExtendedLessons";
lessons.push(...beginnerLessonsExpanded, ...beginnerLessonsSet2, ...intermediateLessons, ...intermediateExtendedLessons, ...advancedLessons);

export function getLessonsByLevel(level: LessonLevel) {
  return lessons.filter((l) => l.level === level);
}

export function getLessonById(id: string) {
  return lessons.find((l) => l.id === id);
}
